OKSnackbarType={Neutral=0,Warning=1,Critical=2,Positive=3}OKSnackbarStyle={Default=0,OneButton=1}OKSnackbarFactory={}function OKSnackbarFactory.show(a,b,c,d,e,f,g)if not OKSnackbar then OKToast.showToastAtBottom(c)return end;if a==nil then a=OKSnackbarType.Neutral end;if b==nil then b=OKSnackbarStyle.Default end;if b==OKSnackbarStyle.OneButton and(not d or d=="")then b=OKSnackbarStyle.Default end;local h=OKSnackbar(a):style(b):descriptionText(c):button(d,e):setCloseAction(f)if h.setAnchor then h:setAnchor(g)end;h:showSnackbar()return h end
